import React, { useRef, useEffect, useState } from "react";
import * as faceapi from "face-api.js";
import axios from "axios";

const Scanner = () => {
  const videoRef = useRef();
  const [modelsLoaded, setModelsLoaded] = useState(false);
  const [consent, setConsent] = useState(false);

  useEffect(() => {
    loadModels();
  }, []);

  const loadModels = async () => {
    const MODEL_URL = "/models";

    await faceapi.nets.tinyFaceDetector.loadFromUri(MODEL_URL);
    await faceapi.nets.faceExpressionNet.loadFromUri(MODEL_URL);
    await faceapi.nets.ageGenderNet.loadFromUri(MODEL_URL);

    setModelsLoaded(true);
    console.log("Models Loaded");
  };

  const startVideo = () => {
    navigator.mediaDevices
      .getUserMedia({ video: true })
      .then((stream) => {
        videoRef.current.srcObject = stream;
      });
  };

  const detectFace = async () => {
    if (!modelsLoaded) {
      alert("Models are still loading...");
      return;
    }

    const detection = await faceapi
      .detectSingleFace(
        videoRef.current,
        new faceapi.TinyFaceDetectorOptions()
      )
      .withFaceExpressions()
      .withAgeAndGender();

    if (!detection) {
      alert("No face detected");
      return;
    }

    const emotion = Object.keys(detection.expressions).reduce((a, b) =>
      detection.expressions[a] > detection.expressions[b] ? a : b
    );

    const result = {
      age: Math.round(detection.age),
      gender: detection.gender,
      emotion,
    };

    await axios.post("http://localhost:5000/api/face-data", result);

    alert("Data Sent Successfully!");
  };

  return (
    <div>
      {!consent && (
        <div>
          <p>This app uses facial analytics. No images stored.</p>
          <button
            onClick={() => {
              setConsent(true);
              startVideo();
            }}
          >
            Agree & Start
          </button>
        </div>
      )}

      <video ref={videoRef} autoPlay muted width="500" />
      <br />
      <button onClick={detectFace} disabled={!modelsLoaded}>
        {modelsLoaded ? "Scan" : "Loading Models..."}
      </button>
    </div>
  );
};

export default Scanner;
